#include <bits/stdc++.h>
using namespace std;
#define int long long
const int mod=998244353;
int ans;
int ksm(int n,int m){
	int s=1;
	while(m){
		if(m&1){
			s=s*n%mod;
		}
		n=n*n%mod;
		m>>=1;
	}
	return s;
}
int n,k;
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>k;
	ans=ksm(ksm(2,k)-1,n);
	cout<<ans;
	return 0;
}
